--Menu
    ["menu_accessibility_screenflash_color_blurzone_multi_option"] = "Цвет вспышки размытия", --Цвет мигания в зоне размытия
	["menu_accessibility_screenflash_color_blurzone_multi_option_help"] = "(eng: Blur Zone Flash Color) Установите альтернативный цвет для мигания экрана, которое появляется при размытии изображения. Цвет по умолчанию - желтый, на фильтр размытия это не влияет.",
    ["menu_accessibility_screenflash_color_hit_flash_multi_option"] = "Цвет вспышки при уроне",
	["menu_accessibility_screenflash_color_hit_flash_multi_option_help"] = "(eng: Damage Flash Color) Установите альтернативный цвет для мигания экрана, которое появляется при получении или уклонении от урона. Цвет по умолчанию - желтый, эффект по умолчанию отключен.",
    ["menu_accessibility_screenflash_color_multi_option"] = "Цвет вспышки", --Цвет вспышки на экране
	["menu_accessibility_screenflash_color_multi_option_help"] = "(eng: Screen Flash Color) Установите альтернативный цвет для ярких вспышек на экране, предназначенных для ослепления игрока, например, от светошумовых гранат. Цвет по умолчанию - белый. Если совокупная интенсивность эффектов вспышки на экране превысит определенный порог, вместо него будет использоваться этот цвет",
    ["menu_accessibility_sounds_tinnitus_toggle"] = "Отключить звук звона в ушах",
	["menu_accessibility_sounds_tinnitus_toggle_help"] = "(eng: Disable Tinnitus Ringing Effect) Отключает звуковой эффект звона в ушах, который воспроизводится при воздействии светошумовых гранат или взрывов.",

    ["menu_equipment_grenade_crate"] = "Сумка с боеприпасами",
    ["menu_equipment_spy_camera"] = "Камера-шпион",
    ["menu_in33_desc_weapon_color_multiple"] = "Это гарантирует, что ваш рабочий инструмент будет выглядеть соответствующим образом, придавая ему стиль, достойный вашего растущего списка преступных заслуг.",
    ["menu_l_global_value_esp"] = "Это предмет из Espionage Weapon Pack!",
    ["menu_l_global_value_unk"] = "Это предмет из PUBG: BATTLEGROUNDS!",
    ["menu_nh_esp_dlc"] = "Почувствуйте себя шпионом, новое DLC уже вышло!",
    ["menu_nh_dgs_02"] = "Получите весь контент PAYDAY 2 в одном наборе!",
    ["menu_nh_corp"] = "Доступны новые Twitch Drops!",

    ["menu_permission_help"] = "Установите, кто сможет присоединиться к этой игре. К открытой игре может присоединиться любой желающий, в то время как к игре для друзей и избранных могут присоединиться только пользователи из вашего списка друзей или избранного. Приватные игры доступны только по приглашению.",
    ["menu_pp_asset_ranc_ace_driver"] = "Первоклассный водитель (Скрытно)",
    ["menu_pp_asset_ranc_ace_driver_desc"] = "Нанять более опытного водителя, который прибудет быстрее, чтобы забрать добычу (только для скрытного прохождения).",
    ["menu_pp_asset_ranc_extra_weapon_parts"] = "Дополнительные детали оружия",
    ["menu_pp_asset_ranc_extra_weapon_parts_desc"] = "На ранчо Мидленд только что прибыла дополнительная партия оружейных деталей. Они ваши, забирайте.",
    ["menu_pp_asset_ranc_marked_crate"] = "Пометить ящики с деталями оружия",
    ["menu_pp_asset_ranc_marked_crate_desc"] = "Помечает ящики с оружейными деталями, чтобы их было проще идентифицировать, не открывая.",
    ["menu_pp_asset_ranc_plane_loot_secure"] = "Эвакуация добычи самолётом Фултона (Громко)",
    ["menu_pp_asset_ranc_plane_loot_secure_desc"] = "Доставка добычи на самолет с помощью воздушного шара и клетки  (только для громкого прохождения).",
    ["menu_pp_asset_ranc_reduce_countermeasure"] = "Контрмеры (Скрытно)",
    ["menu_pp_asset_ranc_reduce_countermeasure_desc"] = "Снижает риск срабатывания защитных контрмер во время ограбления, которые вызовут тревогу полиции, если их не отключить (только для скрытного прохождения).",

    ["menu_pp_deep_bpr_loc_a"] = "Аварийный причал",
    ["menu_pp_deep_bpr_loc_b"] = "Уровень A",
    ["menu_pp_deep_bpr_loc_c"] = "Уровень B",
    ["menu_pp_deep_bpr_loc_d"] = "Уровень C",
    ["menu_pp_deep_bpr_loc_e"] = "Уровень D",
    ["menu_pp_ranc_bpr_loc_a"] = "Ранчо Мидленд",

    ["menu_screenflash_color_black"] = "Чёрный",
    ["menu_screenflash_color_dark_grey"] = "Тёмно-серый",
    ["menu_screenflash_color_default"] = "По умолчанию",
    ["menu_screenflash_color_light_grey"] = "Светло-серый",
    ["menu_screenflash_color_mid_grey"] = "Серый",
    ["menu_screenflash_color_off"] = "Выкл.",
    ["menu_st_category_all"] = "Все",
    ["menu_st_category_covert"] = "Скрытные",
    ["menu_st_category_defensive"] = "Защитные",
    ["menu_st_category_favorites"] = "Избранное",
    ["menu_st_category_offensive"] = "Штурмовые",
    ["menu_st_category_stealth"] = "Стелс",
    ["menu_st_category_supportive"] = "Поддержка",
    ["menu_st_category_versatile"] = "Универсальные",
    ["menu_st_spec_23"] = "Имитатор",
    ["menu_st_spec_23_desc"] = "Обладая эйдетической памятью и фотографическими рефлексами, Имитатор представляет собой уникальное физическое явление. Умение предугадывать движения сделало вас невероятно быстрыми на подъём, вплоть до того, что вы можете с лёгкостью уклоняться от пуль и даже отражать их. Вы внимательно изучили другие колоды перков и теперь можете копировать их базовые способности для улучшения собственных сил. Сочетайте и комбинируйте техники, чтобы создать неповторимый и индивидуальный стиль. Если другие обвинят вас в краже, напомните им, что подражание - это искренняя форма лести.",
    ["menu_toggle_alt_hud_ammo"] = "Показывать запас патронов",
    ["menu_toggle_alt_hud_ammo_help"] = "Показывать запасные патроны вместо общего количества патронов в игровом HUD.",
    ["menu_window_mode"] = "Режим экрана",
    ["menu_window_mode_borderless"] = "В окне без рамки",
    ["menu_window_mode_fullscreen"] = "Полноэкранный",
    ["menu_window_mode_help"] = "Установите режим отображения окна. Полноэкранный режим оптимизирует производительность. Оконный режим позволяет переключаться на другие задачи. Режим без рамки сочетает в себе лучшее из обоих миров.",
    ["menu_window_mode_windowed"] = "В окне",
    ["mutator_piggybank"] = "Праздничное событие",
    ["mutator_piggybank_desc"] = "Убивайте врагов в голову или из Денежного бластера, чтобы зарабатывать сумки со свинскими баксами, а затем вносите их в свинью-копилку, чтобы она росла!",
    ["mutator_piggyrevenge_desc"] = "Убивайте врагов, чтобы зарабатывать сумки со свинскими баксами, а затем кормите ими свинью-копилку, чтобы получать баффы и бонусы!",

--Перки
    ["menu_deck10_1_short"] = "Подобранные патроны лечат вас.",
    ["menu_deck10_3_short"] = "Подобранные патроны также дают боеприпасы союзникам.",
    ["menu_deck10_5_short"] = "Подобранные патроны также лечат союзников.",
    ["menu_deck10_9_short"] = "Увеличивает здоровье, получаемое от коробок с патронами, ещё на ##$multiperk;##.",
    ["menu_deck11_9_short"] = "Нанесение урона врагу теперь восстанавливает ##$multiperk;## ед. здоровья каждые ##$multiperk2;## сек. в течение ##$multiperk3;## сек.\n\nШанс пробить вражескую броню увеличен на ##$multiperk4;##.",
    ["menu_deck12_1_short"] = "Чем ниже ваше здоровье, тем выше скорость восстановления брони. Когда ваше здоровье падает ниже ##$multiperk;##, вы получаете до ##$multiperk2;## к скорости восстановления брони.",
    ["menu_deck12_9_short"] = "Все эффекты состояния \"Берсерк\" в этой колоде перков будут срабатывать при ##$multiperk;## здоровья вместо ##$multiperk2;##.",
    ["menu_deck13_1_short"] = "Пока у вас есть броня, вы будете накапливать ##$multiperk;## ед. здоровья за каждых ##$multiperk2;## врагов, убитых вами или вашей командой. Когда броня восстановится после полного уничтожения, вы получите здоровье, равное накопленному количеству. Максимальное количество накапливаемого здоровья зависит от надетой брони.",
    ["menu_deck13_9_short"] = "Убийство врага ускоряет восстановление вашей брони в зависимости от того, сколько у вас брони. Чем больше брони, тем меньше прирост скорости за убийство.\nСкорость восстановления брони сбрасывается каждый раз, когда броня полностью восстанавливается.",
    ["menu_deck14_9_short"] = "Поглощение урона от зарядов \"Истерии\" на вас увеличено на ##$multiperk;##.",
    ["menu_deck15_9_short"] = "Нанесение урона восполнит вам ##$multiperk;## брони - это может происходить не чаще одного раза в ##$multiperk2;## сек.",
    ["menu_deck16_9_short"] = "Каждые ##$multiperk;## отсутствующей брони сокращают время перезарядки восстановления здоровья за убийство на ##$multiperk3;## сек.",
    ["menu_deck17_1_short"] = "Открывает и экипирует инъектор \"Вора в законе\", заменяя текущее метательное оружие. Инъектор излечит вас на ##$multiperk;## от всего полученного урона в течение ##$multiperk2;## сек. Инъектор можно использовать только один раз в ##$multiperk3;## сек.",
    ["menu_deck17_9_short"] = "Вы получаете на ##$multiperk;## больше здоровья. За каждые ##$multiperk3;## ед. здоровья, полученные во время действия инъектора при максимальном запасе здоровья, время перезарядки инъектора сокращается на ##$multiperk4;## сек.",
    ["menu_deck18_1_short"] = "Открывает и экипирует дымовую шашку, заменяя текущее метательное оружие. При активации дымовая шашка создает дымовую завесу, которая держится ##$multiperk;## сек. Находясь внутри завесы, все игроки автоматически уклоняются от ##$multiperk2;## летящих пуль. Точность врагов, находящихся в дыму, снижается на ##$multiperk4;##. Дымовая шашка требует ##$multiperk3;## сек. на перезарядку, но убийство врагов сокращает это время на ##$multiperk5;## сек.",
    ["menu_deck18_9_short"] = "Все эффекты вашей колоды перков увеличиваются на ##$multiperk;##, пока вы стоите в дымовой завесе. Любые союзники, находящиеся в дымовой завесе, получают ##$multiperk2;## к шансу уклонения.",
    ["menu_deck19_1_short"] = "Открывает и экипирует карманную флягу, заменяя текущее метательное оружие. Получаемый урон теперь снижается на ##$multiperk;##, а отложенный урон будет наноситься постепенно (в течение ##$multiperk2;## сек.). Использование фляги мгновенно обнуляет весь текущий отложенный урон. Перезарядка фляги составляет ##$multiperk3;## сек., но оставшееся время уменьшается на 1 секунду за каждого убитого врага.",
    ["menu_deck19_9_short"] = "При снятии отложенного урона вы дополнительно излечитесь на ##$multiperk;## от количества оставшегося на данный момент отложенного урона.",
    ["menu_deck1_9_short"] = "Вы и ваша команда получите ##$multiperk;## к макс. здоровью и ##$multiperk2;## к выносливости за каждого заложника (эффект суммируется до ##$multiperk3;## раз).\n\nВы и ваша команда получите ##$multiperk4;## к снижению урона, если удерживаете одного или более заложников.\n\nПримечание: командные перки не суммируются между собой.",
    ["menu_deck20_1_short"] = "Открывает и экипирует газовый дозатор, заменяя текущее метательное оружие. Для активации необходимо посмотреть на союзника в радиусе ##$multiperk;## метров в прямой видимости и нажать клавишу метательного оружия ##$BTN_ABILITY;##, чтобы пометить его. Каждый враг, убитый вами или помеченным союзником, теперь будет восстанавливать вам ##$multiperk2;## здоровья, а помеченному союзнику - ##$multiperk3;## здоровья. Ваши убийства продлевают действие эффекта на ##$multiperk4;## сек. и сокращают время перезарядки на 2 секунды. Эффект длится ##$multiperk5;## сек. и имеет перезарядку в ##$multiperk6;## сек.",
    ["menu_deck20_9_short"] = "Каждый враг, убитый помеченным союзником, теперь сокращает время перезарядки предмета вашей колоды перков на ##$multiperk;## сек., пока вы работаете в паре.",
    ["menu_deck21_1_short"] = "Открывает и экипирует карманный генератор помех.",
    ["menu_deck21_9_short"] = "Члены команды, убивающие врагов во время действия эффекта обратной связи, восстанавливают ##$multiperk;## здоровья. Ваш шанс уклонения увеличен ещё на ##$multiperk2;##.",
    ["menu_deck22_1_short"] = "Открывает и экипирует  \"Ампулу Кровопийцы\", заменяя текущее метательное оружие, которая восстанавливает ##$multiperk;## здоровья, отключает вашу броню и делит ваше здоровье на сегменты. Получение урона убирает один сегмент. Попадания, наносящие более 200 единиц урона, убирают два сегмента. Убийство ##$multiperk3;## врагов восстанавливает один сегмент здоровья. Когда вы получаете урон, ваши товарищи по команде лечатся на ##$multiperk4;##. Действие ампулы длится ##$multiperk5;## сек. с перезарядкой в ##$multiperk6;## сек.",
    ["menu_deck22_3_short"] = "Ваш максимальный запас здоровья увеличен на ##$multiperk;##. Пока активна \"Ампула Кровопийцы\", вы не можете упасть.",
    ["menu_deck22_9_short"] = "Теперь вы можете активировать \"Ампулу Кровопийцы, находясь в состоянии падения, что временно поднимет вас. Если вы успешно реанимируете товарища по команде или воспользуетесь медицинской сумкой до окончания действия ампулы, вы останетесь живы.",
    ["menu_deck2_9_short"] = "Вы получаете дополнительные ##$multiperk;## к макс. здоровью.\n\nВы регенерируете ##$multiperk2;## от своего здоровья каждые ##$multiperk3;## сек.",
    ["menu_deck3_9_short"] = "Вы получаете дополнительные ##$multiperk;## к объёму брони.\n\nСокращает время восстановления брони для вас и вашей команды на ##$multiperk2;##.\n\nПримечание: командные перки не суммируются.",
    ["menu_deck4_9_short"] = "Все ваше оружие имеет шанс ##$multiperk;## пробить вражескую броню.\n\nУвеличивает скорость смены оружия на ##$multiperk2;##.",
    ["menu_deck5_9_short"] = "Скорость восстановления вашей брони увеличена ещё на ##$multiperk;##.\n\nВаша броня восстановится через ##$multiperk6;## сек. после уничтожения независимо от ситуации.",
    ["menu_deck6_9_short"] = "Скорость восстановления вашей брони увеличена на ##$multiperk;##.",
    ["menu_deck7_9_short"] = "Нахождение на месте и в положении пригнувшись увеличивает скорость восстановления брони на ##$multiperk;##.\n\nВы получаете ##$multiperk2;## к скорости перемещения пригнувшись.",
    ["menu_deck8_5_desc"] = "Когда вы находитесь на средней дистанции от врага, вы получаете на ##$multiperk;## меньше урона от врагов.\n\nКогда активен ваш буст урона в ближнем бою, лимит времени между последовательными ударами теперь составляет ##$multiperk3;## сек.",
    ["menu_deck8_5_short"] = "Находясь на средней дистанции от врага, вы получаете на ##$multiperk;## меньше урона.\n\nКаждый успешный удар ближнего боя дает ##$multiperk2;## к урону в ближнем бою на ##$multiperk3;## сек. и может суммироваться до ##$multiperk4;## раз.",
    ["menu_deck8_7_short"] = "Когда вас окружают три или более врага, вы получаете на ##$multiperk;## меньше урона.\n\nВаш второй и каждый последующий удар ближнего боя в течение ##$multiperk2;## сек. друг от друга наносят в ##$multiperk3;## раза больше обычного урона.",
    ["menu_deck8_9_short"] = "Удар по врагу оружием ближнего боя восстанавливает ##$multiperk;## вашего здоровья. Это не может происходить чаще одного раза в ##$multiperk2;## сек.",
    ["menu_deck9_1_short"] = "Когда вас окружают три или более врага, вы получаете на ##$multiperk;## меньше урона. Каждый ваш удар ближнего боя, нанесенный в течение ##$multiperk2;## сек. после предыдущего, нанесет в ##$multiperk3;## раза больше обычного урона.",
    ["menu_deck9_3_short"] = "Убийство врага восстанавливает ##$multiperk;## брони. Вы также получаете дополнительные ##$multiperk3;## к объёму брони.",
    ["menu_deck9_9_short"] = "Убийство врага на средней дистанции имеет шанс ##$multiperk;## вызвать панику среди ваших врагов.\n\nПаника заставит врагов впадать в кратковременные приступы неконтролируемого страха. Это не может происходить чаще одного раза в ##$multiperk2;## сек.",

